script.text:
      &ScriptVoucherInit;

function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');&InitFormVisibleField;&InitFormDetailTax;}
function active$Voucher$(f) {&ScriptActiveVoucher;&ExportActiveVoucher;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (f._usedDP) {
    f._gridDP = f.getItem('p&Tag;')._controlBehavior;
    f._gridDP.add_onRender(on$Voucher$GridDownPaymentRender);
  }
  if (!f._printList) setFormHiddenFields(f, ['so_bk', 'ngay_bk']);
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&LoadFormVisibleField;&LoadFormDetailTax;
  &EnvironmentTaxAddRender;&VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
      &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&VoucherLogHandleStatus;
}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._usedDP) try {f._gridDP.remove_onRender(on$Voucher$GridDownPaymentRender);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &EnvironmentTaxRemoveRender;
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d81')._controlBehavior;
  switch (action) {
    case 'Save':
      f.getItem('ma_kh2').field.AllowNulls = (f.getItemValue('thue_cn') == 0);
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      if (f._usedDP) {
        f._gridDP.setSequenceNumber('line_nbr');
        f._gridDP.setContinuance('stt_rec0');
      }
      break;
    case 'Explore':
    &CancelStatusExplore;
    &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function setFormHiddenFields(f, a) {
  for (var i = 0; i < a.length; i++) {
    $common.setVisible(f.getItem(a[i]).parentNode.parentNode.parentNode, false);
  }
}
/* </flatten> */

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d81')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt2,t_thue_nt,t_tt_nt,t_tien_nt,t_tc_tien_nt2,t_ck_nt,t_km_nt,t_km_ct_nt,t_thue_km_nt,t_tien_km_nt:t_tien2,t_thue,t_tt,t_tien,t_tc_tien2,t_ck,t_km,t_km_ct,t_thue_km,t_tien_km');

    var $dt = {};
    $dt.aGridFields = 'gia_nt2,tien_nt2,ck_nt,gia_nt,tien_nt:gia2,tien2,ck,gia,tien';
    $dt.aTotalFields = [['t_tien_nt2', '[tien_nt2] - [ck_nt]', '[km_yn] == 0'],['t_tien2', '[tien2] - [ck]', '[km_yn] == 0'],['t_tien_nt', 'tien_nt'],['t_tien', 'tien'],['t_tc_tien_nt2', 'tien_nt2'],['t_tc_tien2', 'tien2'],['t_ck_nt', 'ck_nt'],['t_ck', 'ck'],['t_km_nt', 'tien_nt2', '[km_yn] != 0'],['t_km', 'tien2', '[km_yn] != 0'],['t_km_ct_nt', 'tien_nt2', '(([km_yn] == 2) || ([km_yn] == 3))'],['t_km_ct', 'tien2', '(([km_yn] == 2) || ([km_yn] == 3))']];
    &DetailTaxCurrencyCreate;

    v.addGridFields(g, $dt.aGridFields);
    v.addTotalFields(g, $dt.aTotalFields);
    v.set_referenceFields(null);
    v.set_executeExpression($dt.aExpression);
    &EnvironmentTaxGridFields;
    &CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    var f = sender.get_element().parentForm;
    if (e.object._baseCurrency == e.type) {
      focus$Voucher$Tab(f, true);
      &PostCurrencySelected;
    }
    if (f._usedDP) set$Voucher$GridColumns(f._gridDP);
  }
}


function onChange$Voucher$Tab(sender, e) {focus$Voucher$Tab(sender.parentForm);&PostTabFocus;}
function focus$Voucher$Tab(f, force) {
  var c = &DetailTaxFormTabFocus;, a = force ? [['d81', c]] : ['d81'];
  &ExportFocusVoucherTab;
  if (f._usedDP) Array.add(a, force ? ['p81', c] : 'p81');
  Array.add(a, 'so_ct_goc');
  if (f._usedEI) Array.add(a, 'sd_hddt_yn');
  &ListTabChange;
  &PostTabChange;
  Array.add(a, 'ma_nvbh');
  f.focusWhenTabChanged(a);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$DebitAccount(o) {o.parentForm.request('DebitAccount', 'DebitAccount', ['tk'], o);}
function onChange$Voucher$TaxCode(o) {o.parentForm.request('GetTaxRate', 'GetTaxRate', ['ma_thue'], o);}
function onChange$Voucher$TaxAccount(o) {o.parentForm.request('TaxAccount', 'TaxAccount', ['tk_thue_co'], o);}
function onChange$Voucher$ForeignCurrencyTaxAmount(e) {
  var f = e.parentForm, o = f.getItem('t_thue');
  f.executeExpression(['[t_thue]:=[t_thue_nt]*[ty_gia]', '[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]', '[t_tt]:=[t_tien2]+[t_thue]']);
  f.live(o);
}
function onChange$Voucher$BaseCurrencyTaxAmount(e) {e.parentForm.executeExpression(['[t_tt]:=[t_tien2]+[t_thue]']);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
/* </flatten> */



function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      set$Voucher$DefaultValue(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      set$Voucher$DefaultValue(f);
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &EnvironmentTaxCurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('tk_thue_no', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ma_tt', result[2].Value, result[3].Value, &ResetCustInfoFields;);
      f.setItemControlBehavior('ten_khthue', result[4].Value, null, true);
      f.setItemControlBehavior('ong_ba', result[5].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('dia_chithue', result[6].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_so_thue', result[7].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_nvbh', result[8].Value, result[9].Value, &ResetCustInfoFields;);
      &EICustomerResponseComplete;
      f.live(f.getItem('ong_ba'));
      break;
    case 'DebitAccount':
      f.setItemControlBehavior('tk_thue_no', result[0].Value, '');
      break;
    case 'GetTaxRate':
      var r = result[0].Value, g = f.getItem('d81')._controlBehavior;
      if (f.getItemValue('thue_suat') != r) {
        f.setItemValue('thue_suat', r);
        g.executeAggregate([g.$a.t_km_ct_nt, g.$a.t_km_ct]);
        f.executeExpression(['[t_thue_nt]:=[t_tien_nt2]*[thue_suat]/100', '[t_thue]:=[t_tien2]*[thue_suat]/100', '[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]', '[t_tt]:=[t_tien2]+[t_thue]']);
        f.executeExpression([g.$a.t_thue_km_nt, g.$a.t_thue_km, g.$a.t_tien_km_nt, g.$a.t_tien_km]);
      }
      f.setItemControlBehavior('tk_thue_co', result[1].Value, '', true);
      f.setItemValue('thue_cn', result[2].Value);
      break;
    case 'TaxAccount':
      f.setItemValue('thue_cn', result[0].Value);
      break;
    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      break;
    &EIResponseCompleteChecking;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
function set$Voucher$DefaultValue(f) {
  &DetailTaxFormDefaultValue;
}
function when$VoucherCopying(f) {f.setItemValue('stt_rec', '');&DetailTaxVoucherCopying;}

